using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1. Strongly-typed metadata retrieval: GetTypeInfo<T>()
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
// In .NET 9+ there's a generic helper – but the public API is:
//   options.GetTypeInfo(typeof(T)) returning JsonTypeInfo, then cast.
// However, we can use the typed overload on JsonSerializerOptions:
JsonTypeInfo<Person> typedInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for Person: {typedInfo.Type.Name}");

// 2. Probe without throwing: TryGetTypeInfo()
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    Console.WriteLine($"TryGetTypeInfo(Person) succeeded: {found!.Type.Name}");
}

// Now try a type that has NO resolver (use bare options with no resolver)
var empty = new JsonSerializerOptions();   // no TypeInfoResolver set
if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? notFound))
{
    Console.WriteLine("Unexpected: found metadata");
}
else
{
    Console.WriteLine("TryGetTypeInfo(Person) on empty options: not available (no exception)");
}

public record Person(string Name, int Age);

